namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Forklift A", "Warehouse 1", new DateTime(2026, 3, 15)),
            new(2, "Conveyor Belt B", "Warehouse 2", new DateTime(2026, 4, 20)),
            new(3, "Pallet Jack C", "Loading Dock", new DateTime(2026, 5, 1)),
            new(4, "Crane D", "Yard North", new DateTime(2026, 2, 10)),
            new(5, "Compressor E", "Maintenance Bay", new DateTime(2026, 1, 22)),
            new(6, "Generator F", "Utility Room", new DateTime(2025, 12, 5)),
            new(7, "Welding Station G", "Shop Floor", new DateTime(2026, 4, 8)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@attribute [StreamRendering]
@using InventoryApp.Services
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("inventory", out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("inventory", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

